import { Router } from "express";
import { createContact, deleteContact, getAllContacts, getContactById, markContactAsReplied, updateContact, } from "./contact.controller.js";
import { validateContactInput } from "./contact.validator.js";
import { authMiddleware, authorize } from "../middlewares/auth.middleware.js";
import { CONTENT_ROLES } from "../constants/roles.js";
const router = Router();
router.post("/", validateContactInput, createContact);
router.get("/", authMiddleware, authorize(...CONTENT_ROLES), getAllContacts);
router.get("/:id", authMiddleware, authorize(...CONTENT_ROLES), getContactById);
router.put("/:id", authMiddleware, authorize(...CONTENT_ROLES), updateContact);
router.patch("/:id/reply", authMiddleware, authorize(...CONTENT_ROLES), markContactAsReplied);
router.delete("/:id", authMiddleware, authorize(...CONTENT_ROLES), deleteContact);
export default router;
